CREATE TABLE IF NOT EXISTS ship_event_attachments (ship_event_id INT, "number" INT, url VARCHAR(1000) NOT NULL, first_seen INT NOT NULL, last_seen INT NOT NULL, CONSTRAINT pk_ship_event_attachments PRIMARY KEY (ship_event_id, "number"), CONSTRAINT fk_ship_event_attachments_ship_event_id__internal_id FOREIGN KEY (ship_event_id) REFERENCES ship_events(internal_id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_ship_event_attachments_first_seen__id FOREIGN KEY (first_seen) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_ship_event_attachments_last_seen__id FOREIGN KEY (last_seen) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT);